import sysfrom pathlib import Pathimport jsonimport joblibimport numpy as npimport pandas as pdfrom sklearn.linear_model import LogisticRegressionfrom sklearn.metrics import (    accuracy_score,    classification_report,    confusion_matrix,    f1_score,)# path setupPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import (    PROCESSED_DATA_DIR,    BASELINE_MODELS_DIR,    REPORTS_DIR,    TABLE_DIR,    INTERIM_DATA_DIR,)DATASET_TAG = "large_lite"EXPERIMENT_TAG = "sif_threshold_only_v1"LABEL_COL = "label_5d"# ===== load =====def load_labels():    train = pd.read_parquet(PROCESSED_DATA_DIR / "train_doc_5d_large_lite.parquet", columns=[LABEL_COL])    val = pd.read_parquet(PROCESSED_DATA_DIR / "validation_doc_5d_large_lite.parquet", columns=[LABEL_COL])    test = pd.read_parquet(PROCESSED_DATA_DIR / "test_doc_5d_large_lite.parquet", columns=[LABEL_COL])    return (        train[LABEL_COL].values,        val[LABEL_COL].values,        test[LABEL_COL].values,    )def load_embeddings():    X_train = np.load(INTERIM_DATA_DIR / "train_doc_embedding_word2vec_large_lite.npy")    X_val = np.load(INTERIM_DATA_DIR / "validation_doc_embedding_word2vec_large_lite.npy")    X_test = np.load(INTERIM_DATA_DIR / "test_doc_embedding_word2vec_large_lite.npy")    return X_train, X_val, X_test# ===== utils =====def predict_with_threshold(proba, threshold):    return (proba >= threshold).astype(int)# ===== main tuning =====def main():    print("Loading embeddings...")    X_train, X_val, X_test = load_embeddings()    print("Loading labels...")    y_train, y_val, y_test = load_labels()    print("\nTraining Logistic Regression (fixed C=0.1)...")    clf = LogisticRegression(        C=0.1,        max_iter=2000,        random_state=42,    )    clf.fit(X_train, y_train)    val_proba = clf.predict_proba(X_val)[:, 1]    thresholds = [0.45, 0.50, 0.55, 0.60, 0.65, 0.70, 0.75]    results = []    best = None    print("\nSearching best threshold...")    for t in thresholds:        val_pred = predict_with_threshold(val_proba, t)        acc = accuracy_score(y_val, val_pred)        f1 = f1_score(y_val, val_pred)        result = {            "threshold": t,            "val_accuracy": acc,            "val_f1": f1,        }        results.append(result)        print(f"Threshold={t:.2f} | Acc={acc:.4f} | F1={f1:.4f}")        if best is None or f1 > best["val_f1"]:            best = result    print("\nBest threshold:")    print(best)    # ===== test =====    test_proba = clf.predict_proba(X_test)[:, 1]    best_t = best["threshold"]    test_pred = predict_with_threshold(test_proba, best_t)    test_acc = accuracy_score(y_test, test_pred)    test_f1 = f1_score(y_test, test_pred)    cm = confusion_matrix(y_test, test_pred)    report = classification_report(y_test, test_pred, output_dict=True)    print("\n=== TEST PERFORMANCE ===")    print(f"Threshold:     {best_t}")    print(f"Test Accuracy: {test_acc:.4f}")    print(f"Test F1:       {test_f1:.4f}")    print("Confusion Matrix:")    print(cm)    # ===== save =====    BASELINE_MODELS_DIR.mkdir(parents=True, exist_ok=True)    REPORTS_DIR.mkdir(parents=True, exist_ok=True)    TABLE_DIR.mkdir(parents=True, exist_ok=True)    model_path = BASELINE_MODELS_DIR / f"word2vec_logistic_{DATASET_TAG}_{EXPERIMENT_TAG}.joblib"    report_path = REPORTS_DIR / f"word2vec_logistic_{DATASET_TAG}_{EXPERIMENT_TAG}_results.json"    table_path = TABLE_DIR / f"word2vec_logistic_{DATASET_TAG}_{EXPERIMENT_TAG}_validation_results.csv"    joblib.dump(clf, model_path)    pd.DataFrame(results).to_csv(table_path, index=False)    payload = {        "experiment_tag": EXPERIMENT_TAG,        "best_validation": best,        "test_results": {            "accuracy": test_acc,            "f1": test_f1,            "confusion_matrix": cm.tolist(),        },    }    with open(report_path, "w") as f:        json.dump(payload, f, indent=2)    print("\nSaved outputs:")    print(model_path)    print(report_path)    print(table_path)    print("\nDone.")if __name__ == "__main__":    main()